import React, { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import './Hero.css';

const statItems = [
  { label: '오늘의 체크인', value: '1.2만+', tone: 'purple' },
  { label: '누적 대화 세션', value: '8.4만+', tone: 'blue' },
  { label: '감정 리포트 생성', value: '3.1만+', tone: 'mint' },
];

const floatingCards = [
  { title: '감정 체크인', body: '오늘 기분을 가볍게 남겨요', tone: 'yellow' },
  { title: '대화 시작', body: '캐릭터가 먼저 반응해요', tone: 'purple' },
  { title: '주간 리포트', body: '이번 주 흐름을 정리해줘요', tone: 'pink' },
];

export default function Hero() {
  const [scrollRatio, setScrollRatio] = useState(0);
  const [scrollState, setScrollState] = useState('idle');

  useEffect(() => {
    const onScroll = () => {
      const y = window.scrollY || 0;
      const ratio = Math.min(y / 520, 1);
      setScrollRatio(ratio);

      if (y < 80) setScrollState('idle');
      else if (y < 320) setScrollState('wave');
      else setScrollState('react');
    };

    onScroll();
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const reactionText = useMemo(() => {
    if (scrollState === 'wave') return '앗, 스크롤하고 있네요. 반갑게 인사할게요!';
    if (scrollState === 'react') return '좋아요. 아래 기능들도 같이 살펴보면 더 재밌어요.';
    return '안녕하세요. 오늘 마음을 함께 돌봐드릴게요.';
  }, [scrollState]);

  return (
    <section className="cutehero-section" style={{ '--hero-scroll': scrollRatio }}>
      <div className="cutehero-bg cutehero-bg--one" />
      <div className="cutehero-bg cutehero-bg--two" />
      <div className="cutehero-bg cutehero-bg--three" />

      <div className="cutehero-container">
        <div className="cutehero-grid">
          <div className="cutehero-copy">
            <span className="cutehero-kicker">Virtual Care Companion</span>

            <h1>
              오늘의 마음을
              <br />
              <strong>조금 더 다정하고 귀엽게 돌봐주는 AI 캐릭터</strong>
            </h1>

            <p>
              단순한 챗봇이 아니라, 화면 안에 살아 있는 것처럼 반응하는 버추얼 캐릭터와
              함께 감정 체크인, 대화, 일기, 리포트를 자연스럽게 이어갈 수 있어요.
            </p>

            <div className="cutehero-actions">
              <Link to="/chat" className="cutehero-btn cutehero-btn--primary">
                캐릭터와 대화 시작하기
              </Link>
              <Link to="/signup" className="cutehero-btn cutehero-btn--ghost">
                무료로 시작하기
              </Link>
            </div>

            <div className="cutehero-stats">
              {statItems.map((item) => (
                <div
                  key={item.label}
                  className={`cutehero-stat-card cutehero-stat-card--${item.tone}`}
                >
                  <span>{item.label}</span>
                  <strong>{item.value}</strong>
                </div>
              ))}
            </div>
          </div>

          <div className={`cutehero-visual cutehero-visual--${scrollState}`}>
            <div className="cutehero-visual-card">
              <div className="cutehero-floating cutehero-floating--left">
                <div className="cutehero-mini-card cutehero-mini-card--yellow">
                  <strong>{floatingCards[0].title}</strong>
                  <span>{floatingCards[0].body}</span>
                </div>
              </div>

              <div className="cutehero-floating cutehero-floating--right">
                <div className="cutehero-mini-card cutehero-mini-card--pink">
                  <strong>{floatingCards[2].title}</strong>
                  <span>{floatingCards[2].body}</span>
                </div>
              </div>

              <div className="cutehero-floating cutehero-floating--bottom">
                <div className="cutehero-mini-card cutehero-mini-card--purple">
                  <strong>{floatingCards[1].title}</strong>
                  <span>{floatingCards[1].body}</span>
                </div>
              </div>

              <div className="cutehero-character-stage">
                <div className="cutehero-stage-ring cutehero-stage-ring--one" />
                <div className="cutehero-stage-ring cutehero-stage-ring--two" />
                <div className="cutehero-stage-floor" />

                <div className={`cutehero-character cutehero-character--${scrollState}`}>
                  <div className="cutehero-character__halo" />

                  <div className="cutehero-character__head">
                    <span className="eye left" />
                    <span className="eye right" />
                    <span className={`mouth mood-${scrollState}`} />
                    <span className="cheek left" />
                    <span className="cheek right" />
                  </div>

                  <div className="cutehero-character__body">
                    <span className="core" />
                  </div>

                  <div className="cutehero-character__arm cutehero-character__arm--left" />
                  <div className="cutehero-character__arm cutehero-character__arm--right" />
                </div>

                <div className="cutehero-reaction-bubble">
                  <strong>AI Companion</strong>
                  <p>{reactionText}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
